(function($,window){"use strict";const domain=getAppDomain();$((function(){if($.cookie("Flash.Error")){notify($.cookie("Flash.Error"),"error");$.removeCookie("Flash.Error",{path:"/",domain:domain})}if($.cookie("Flash.Notification")){notify($.cookie("Flash.Notification"),"information");$.removeCookie("Flash.Notification",{path:"/",domain:domain})}if($.cookie("Flash.Success")){notify($.cookie("Flash.Success"),"success");$.removeCookie("Flash.Success",{path:"/",domain:domain})}if($.cookie("Flash.Information")){notify($.cookie("Flash.Information"),"information");$.removeCookie("Flash.Information",{path:"/",domain:domain})}if($.cookie("Flash.Warning")){notify($.cookie("Flash.Warning","error"));$.removeCookie("Flash.Warning",{path:"/",domain:domain})}if($.cookie("Flash.Alert")){notify($.cookie("Flash.Alert"),"information");$.removeCookie("Flash.Alert",{path:"/",domain:domain})}}));function getAppDomain(){const hostname=window.location.hostname;const parts=hostname.split(".");if(parts.length>1)return parts.slice(-2).join(".");return hostname}})(jQuery,window);